import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import Cookie from "cookie-universal";
import Axios, { ADMIN_USERS } from "../../Api/Api";
import "../../Styles/Dashboard.css";

export default function UserManagement() {
  const navigate = useNavigate();
  const cookie = Cookie();

  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [currentUser, setCurrentUser] = useState(null);
  const [formData, setFormData] = useState({
    name: "",
    email: "",
    password: "",
    role: "student",
  });
  const [formLoading, setFormLoading] = useState(false);

  // التحقق من الأدمن
  useEffect(() => {
    const user = cookie.get("educational-user");
    if (!user) {
      navigate("/login");
      return;
    }

    let userData;
    if (typeof user === "string") {
      userData = JSON.parse(user);
    } else {
      userData = user;
    }

    if (userData.role !== "admin") {
      alert("غير مصرح لك بالوصول لهذه الصفحة");
      navigate("/");
      return;
    }

    loadUsers();
  }, []);

  // جلب المستخدمين
  function loadUsers() {
    setLoading(true);
    Axios.get(`/${ADMIN_USERS}`)
      .then((res) => {
        setUsers(res.data);
        setLoading(false);
      })
      .catch((err) => {
        console.error(err);
        setLoading(false);
      });
  }

  // فتح Modal للإضافة
  function openAddModal() {
    setEditMode(false);
    setCurrentUser(null);
    setFormData({
      name: "",
      email: "",
      password: "",
      role: "student",
    });
    setShowModal(true);
  }

  // فتح Modal للتعديل
  function openEditModal(user) {
    setEditMode(true);
    setCurrentUser(user);
    setFormData({
      name: user.name,
      email: user.email,
      password: "",
      role: user.role,
    });
    setShowModal(true);
  }
    // معالجة التغييرات بالـ Form
  function handleChange(e) {
    const { name, value } = e.target;
    setFormData({
      ...formData,
      [name]: value,
    });
  }

  // إضافة/تعديل مستخدم
  async function handleSubmit(e) {
    e.preventDefault();
    setFormLoading(true);

    try {
      const dataToSend = { ...formData };
      
      // إزالة كلمة السر إذا كانت فارغة في وضع التعديل
      if (editMode && !dataToSend.password) {
        delete dataToSend.password;
      }

      if (editMode) {
        await Axios.put(`/${ADMIN_USERS}/${currentUser.id}`, dataToSend);
        alert("تم تعديل المستخدم بنجاح ✅");
      } else {
        await Axios.post(`/${ADMIN_USERS}`, dataToSend);
        alert("تم إضافة المستخدم بنجاح ✅");
      }

      setShowModal(false);
      loadUsers();
      setFormLoading(false);
    } catch (error) {
      console.error(error);
      alert("حدث خطأ: " + (error.response?.data?.message || "حاول مرة أخرى"));
      setFormLoading(false);
    }
  }

  // حذف مستخدم
  async function handleDelete(id, name) {
    if (!window.confirm(`هل أنت متأكد من حذف المستخدم "${name}"؟`)) {
      return;
    }

    try {
      await Axios.delete(`/${ADMIN_USERS}/${id}`);
      alert("تم حذف المستخدم بنجاح ✅");
      loadUsers();
    } catch (error) {
      console.error(error);
      alert("حدث خطأ في الحذف");
    }
  }

  // تغيير الصلاحية فقط
  async function handleRoleChange(userId, newRole) {
    try {
      await Axios.patch(`/${ADMIN_USERS}/${userId}/role`, { role: newRole });
      alert("تم تغيير الصلاحية بنجاح ✅");
      loadUsers();
    } catch (error) {
      console.error(error);
      alert("حدث خطأ في تغيير الصلاحية");
    }
  }

  if (loading) {
    return (
      <div className="loading-container">
        <div className="spinner"></div>
        <p>جاري التحميل...</p>
      </div>
    );
  }
    return (
    <div className="dashboard-page">
      <div className="dashboard-header">
        <div className="container">
          <h1>إدارة المستخدمين 👥</h1>
          <button onClick={openAddModal} className="add-btn">
            ➕ إضافة مستخدم جديد
          </button>
        </div>
      </div>

      <div className="dashboard-content">
        <div className="container">
          <div className="dashboard-nav">
            <button
              onClick={() => navigate("/dashboard")}
              className="nav-btn"
            >
              📚 إدارة الكورسات
            </button>
            <button
              onClick={() => navigate("/dashboard/instructors")}
              className="nav-btn"
            >
              👨‍🏫 إدارة المدرسين
            </button>
            <button
              onClick={() => navigate("/dashboard/users")}
              className="nav-btn active"
            >
              👥 إدارة المستخدمين
            </button>
          </div>

          <div className="stats-cards">
            <div className="stat-card">
              <h3>إجمالي المستخدمين</h3>
              <p className="stat-number">{users.length}</p>
            </div>
            <div className="stat-card">
              <h3>المدراء</h3>
              <p className="stat-number">
                {users.filter((u) => u.role === "admin").length}
              </p>
            </div>
            <div className="stat-card">
              <h3>الطلاب</h3>
              <p className="stat-number">
                {users.filter((u) => u.role === "student").length}
              </p>
            </div>
            <div className="stat-card">
              <h3>المدرسين</h3>
              <p className="stat-number">
                {users.filter((u) => u.role === "instructor").length}
              </p>
            </div>
          </div>

          <div className="table-container">
            <table className="courses-table">
              <thead>
                <tr>
                  <th>ID</th>
                  <th>الاسم</th>
                  <th>البريد الإلكتروني</th>
                  <th>الصلاحية</th>
                  <th>تاريخ التسجيل</th>
                  <th>الإجراءات</th>
                </tr>
              </thead>
              <tbody>
                {users.map((user) => (
                  <tr key={user.id}>
                    <td>{user.id}</td>
                    <td>{user.name}</td>
                    <td>{user.email}</td>
                    <td>
                      <select
                        value={user.role}
                        onChange={(e) => handleRoleChange(user.id, e.target.value)}
                        className="role-select"
                      >
                        <option value="student">طالب</option>
                        <option value="instructor">مدرس</option>
                        <option value="admin">مدير</option>
                      </select>
                    </td>
                    <td>{new Date(user.created_at).toLocaleDateString('ar-EG')}</td>
                    <td>
                      <div className="action-buttons">
                        <button
                          onClick={() => openEditModal(user)}
                          className="edit-btn"
                          title="تعديل"
                        >
                          ✏️
                        </button>
                        <button
                          onClick={() => handleDelete(user.id, user.name)}
                          className="delete-btn"
                          title="حذف"
                        >
                          🗑️
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>
            {/* Modal */}
      {showModal && (
        <div className="modal-overlay" onClick={() => setShowModal(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <h2>{editMode ? "✏️ تعديل المستخدم" : "➕ إضافة مستخدم جديد"}</h2>
              <button onClick={() => setShowModal(false)} className="close-btn">
                ✖
              </button>
            </div>

            <form onSubmit={handleSubmit} className="course-form">
              <div className="form-group">
                <label>الاسم *</label>
                <input
                  type="text"
                  name="name"
                  value={formData.name}
                  onChange={handleChange}
                  required
                  placeholder="أحمد محمد"
                />
              </div>

              <div className="form-group">
                <label>البريد الإلكتروني *</label>
                <input
                  type="email"
                  name="email"
                  value={formData.email}
                  onChange={handleChange}
                  required
                  placeholder="example@domain.com"
                />
              </div>

              <div className="form-group">
                <label>كلمة السر {editMode ? "(اتركها فارغة للإبقاء على القديمة)" : "*"}</label>
                <input
                  type="password"
                  name="password"
                  value={formData.password}
                  onChange={handleChange}
                  required={!editMode}
                  placeholder="••••••"
                  minLength="6"
                />
              </div>

              <div className="form-group">
                <label>الصلاحية *</label>
                <select
                  name="role"
                  value={formData.role}
                  onChange={handleChange}
                  required
                >
                  <option value="student">طالب</option>
                  <option value="instructor">مدرس</option>
                  <option value="admin">مدير</option>
                </select>
              </div>

              <div className="modal-footer">
                <button
                  type="button"
                  onClick={() => setShowModal(false)}
                  className="cancel-btn"
                >
                  إلغاء
                </button>
                <button
                  type="submit"
                  className="submit-btn"
                  disabled={formLoading}
                >
                  {formLoading
                    ? "جاري الحفظ..."
                    : editMode
                      ? "حفظ التعديلات"
                      : "إضافة المستخدم"}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
